let text = msg.payload;

// Eindeutige ID für das Scoping (verhindert CSS-Konflikte im Dashboard)
const uniqueId = "car_ui_" + Math.random().toString(36).substr(2, 9);

const getValue = (regex, input) => {
    const match = input.match(regex);
    return (match && match[1]) ? parseFloat(match[1]) : 0;
};

const getBool = (key, input) => {
    const regex = new RegExp(`['"]${key}['"]\\s*:\\s*(true|false)`, "i");
    const match = input.match(regex);
    if (match) {
        return match[1].toLowerCase() === "true";
    }
    return false;
};

let daten = {
    Reichweite: getValue(/rangeKm['"]\s*:\s*([\d.]+)/, text),
    Tankfüllung: getValue(/levelPct['"]\s*:\s*([\d.]+)/, text),
    ÖlWechsel_Tage: getValue(/oilServiceDueDays['"]\s*:\s*([\d.]+)/, text),
    ÖlWechsel_KM: getValue(/oilServiceDueKm['"]\s*:\s*([\d.]+)/, text),
    Inspektion_Tage: getValue(/inspectionDueDays['"]\s*:\s*([\d.]+)/, text),
    Inspektion_KM: getValue(/inspectionDueKm['"]\s*:\s*([\d.]+)/, text), // NEU
    IstVerschlossen: getBool("locked", text),
    FährtGerade: getBool("isMoving", text)
};

// Status-Logik
let lockClass = daten.IstVerschlossen ? "status-locked" : "status-open";
let lockText = daten.IstVerschlossen ? "Verschlossen" : "Offen";

let moveClass = daten.FährtGerade ? "status-moving" : "normal";
let moveText = daten.FährtGerade ? "Fährt" : "Parkt";

let tankClass = (daten.Tankfüllung < 5) ? "critical-blink" : (daten.Tankfüllung < 20 ? "warning-red" : "normal");

// Logik für Inspektion (Warnung bei weniger als 30 Tagen oder 1500 km)
let inspClass = (daten.Inspektion_Tage < 30 || daten.Inspektion_KM < 1500) ? "warning-orange" : "normal";

msg.payload = `
<style>
    #${uniqueId}.fahrzeug-container {
        display: flex;
        flex-direction: column;
        gap: 6px;
        padding: 5px 5px 5px 70px;
        text-align: left;
    }
    #${uniqueId} .info-row { font-size: 0.9em; line-height: 1.2; color: #ffffff; }
    #${uniqueId} .label { color: #aaaaaa; margin-right: 5px; }

    #${uniqueId} .status-locked { color: #4CAF50; font-weight: bold; }
    #${uniqueId} .status-open { color: #ff9800; font-weight: bold; }
    #${uniqueId} .status-moving { color: #2196F3; font-weight: bold; }
    #${uniqueId} .normal { color: #ffffff; }
    #${uniqueId} .warning-red { color: #ff4d4d; font-weight: bold; }
    #${uniqueId} .warning-orange { color: #ffcc00; font-weight: bold; }

    #${uniqueId} .critical-blink { 
        color: #ff4d4d; 
        font-weight: bold; 
        animation: ${uniqueId}_blinker 1s linear infinite; 
    }
    @keyframes ${uniqueId}_blinker { 50% { opacity: 0.1; } }
</style>

<div id="${uniqueId}" class="fahrzeug-container">
    <div class="info-row">
        <span class="label">Fahrzeug:</span> 
        <span class="${moveClass}">${moveText}</span>
    </div>
    <div class="info-row">
        <span class="label">Sicherheit:</span> 
        <span class="${lockClass}">${lockText}</span>
    </div>
    <div class="info-row">
        <span class="label">Reichweite:</span> 
        <span class="normal">${daten.Reichweite.toLocaleString('de-DE')} km</span>
    </div>
    <div class="info-row">
        <span class="label">Tank:</span> 
        <span class="${tankClass}">${daten.Tankfüllung}%</span>
    </div>
    <div class="info-row">
        <span class="label">Öl-Service:</span> 
        <span class="normal">${daten.ÖlWechsel_Tage} Tage / ${daten.ÖlWechsel_KM.toLocaleString('de-DE')} km</span>
    </div>
    <div class="info-row">
        <span class="label">Inspektion:</span> 
        <span class="${inspClass}">${daten.Inspektion_Tage} Tage / ${daten.Inspektion_KM.toLocaleString('de-DE')} km</span>
    </div>
</div>
`;
return msg;
